{"code": "import json
from datetime import datetime

# Access query results directly from previous tool calls
rl_cases = locals()['var_functions.query_db:0']
rl_accounts = locals()['var_functions.query_db:2']

# Define a function to normalize IDs (strip leading # and whitespace)
def normalize_id(id_str):
    if id_str is None:
        return None
    return id_str.lstrip('#').strip()

# Normalize and parse case data
cases = []
for rec in rl_cases:
    created = rec['createddate']
    closed = rec['closeddate']
    # Parse ISO8601 with timezone offset
    # Use strptime to handle format like 2022-08-05T14:30:00.000+0000
    # The timezone part +0000 is not directly parsed by %z in some Python versions; ensure we handle.
    try:
        created_dt = datetime.strptime(created, '%Y-%m-%dT%H:%M:%S.%f%z')
        closed_dt = datetime.strptime(closed, '%Y-%m-%dT%H:%M:%S.%f%z')
    except Exception as e:
        # In case of format differences, fallback to fromisoformat
        try:
            created_dt = datetime.fromisoformat(created.replace('Z', '+00:00'))
            closed_dt = datetime.fromisoformat(closed.replace('Z', '+00:00'))
        except Exception as e2:
            continue
    duration_min = (closed_dt - created_dt).total_seconds() / 60.0
    cases.append({
        'accountid_norm': normalize_id(rec['accountid']),
        'duration_min': duration_min,
    })

# Build mapping from normalized account ID to state (ShippingState)
account_state = {}
for rec in rl_accounts:
    acc_id = normalize_id(rec['Id'])
    state = rec['ShippingState']
    if state:
        account_state[acc_id] = state.strip()

# Group by state
state_durations = {}
for case in cases:
    state = account_state.get(case['accountid_norm'])
    if not state:
        continue
    state_durations.setdefault(state, []).append(case['duration_min'])

# Compute average, count, total duration per state
state_stats = {}
for state, dur_list in state_durations.items():
    avg = sum(dur_list) / len(dur_list)
    state_stats[state] = {'count': len(dur_list), 'avg_min': avg}

# Sort states by average duration ascending
sorted_states = sorted(state_stats.items(), key=lambda x: x[1]['avg_min'])

# Prepare result
result = {
    'fastest_state': sorted_states[0][0] if sorted_states else None,
    'state_stats': state_stats,
    'sorted_states': [(st, stats['avg_min'], stats['count']) for st, stats in sorted_states]
}
print('__RESULT__:')
print(json.dumps(result))"}
